**Untested functions:**
| Function | Risk |
|---|---|
| `hashPassword()` | bcrypt wrapping — trivial but untested |
| `verifyPassword()` | Returns wrong boolean = login bypass |
| `encryptSession()` | Uses static IV (already a security smell), no test |
| `decryptSession()` | Core auth gate — tampered tokens, malformed input |
| `getSession()` | Cookie missing/invalid |
| `isAdmin()`/`isSiswa()` | Role delegation logic |

**Edge cases not covered:**
- Token without `.` separator → `decryptSession` returns null
- Role prefix mismatch (e.g. `ADMIN.encryptedData` where decrypted says `role: "GURU"`) → line 55 catches this but untested
- Garbage hex data → `createDecipheriv.final()` throws, caught by `catch` returning null
- Empty cookie value → null early return
- Token with extra parts (`A.B.C`) → only reads parts[0] and parts[1], ignores rest — should test

```typescript
// src/lib/__tests__/auth.test.ts
import { decryptSession, encryptSession, getSession, hashPassword, verifyPassword } from '@/lib/auth';
import { NextRequest } from 'next/server';

describe('decryptSession', () => {
  it('returns null for token without dot separator', () => {
    expect(decryptSession('invalidtoken')).toBeNull();
  });

  it('returns null for tampered hex payload', () => {
    expect(decryptSession('ADMIN.garbagehexdata')).toBeNull();
  });

  it('returns null when decrypted role mismatches prefix', () => {
    // Encrypt a GURU session, swap prefix to ADMIN
    const guruToken = encryptSession({ userId: '1', username: 'guru', role: 'GURU', nama: 'Test' });
    const tampered = guruToken.replace(/^[^.]+/, 'ADMIN');
    expect(decryptSession(tampered)).toBeNull();
  });

  it('round-trips a valid session correctly', () => {
    const data = { userId: '1', username: 'admin', role: 'ADMIN' as const, nama: 'Admin' };
    const token = encryptSession(data);
    const result = decryptSession(token);
    expect(result).toEqual(data);
  });
});

describe('hashPassword / verifyPassword', () => {
  it('verifies same password returns true', async () => {
    const hash = await hashPassword('test123');
    expect(await verifyPassword('test123', hash)).toBe(true);
  });

  it('rejects wrong password', async () => {
    const hash = await hashPassword('test123');
    expect(await verifyPassword('wrong', hash)).toBe(false);
  });
});

describe('getSession', () => {
  it('returns null when no session_token cookie', () => {
    const req = { cookies: { get: () => undefined } } as unknown as NextRequest;
    expect(getSession(req)).toBeNull();
  });

  it('returns null when cookie value is empty string', () => {
    const req = { cookies: { get: () => ({ value: '' }) } } as unknown as NextRequest;
    expect(getSession(req)).toBeNull();
  });
});
```

